module parallel2serial(
    input clk,
    input rst_n,
    input [3:0] d,
    output valid_out,
    output dout
);

    reg [3:0] shift_reg;
    reg [1:0] counter;
    reg valid;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            shift_reg <= 4'b0000;
            counter <= 2'b00;
            valid <= 1'b0;
        end else begin
            if (counter == 2'b11) begin
                shift_reg <= d;
                counter <= 2'b00;
                valid <= 1'b1;
            end else begin
                shift_reg <= {shift_reg[2:0], shift_reg[3]};
                counter <= counter + 1'b1;
                valid <= 1'b0;
            end
        end
    end

    assign dout = shift_reg[3];
    assign valid_out = valid;

endmodule
